    private fun parseFileChooserResult(result: ActivityResult): Array<Uri>? {
        if (result.resultCode != Activity.RESULT_OK) return null
        val data = result.data
        val clip = data?.clipData
        if (clip != null && clip.itemCount > 0) {
            val list = ArrayList<Uri>(clip.itemCount)
            for (i in 0 until clip.itemCount) {
                val item = clip.getItemAt(i)
                item?.uri?.let { list.add(it) }
            }
            return if (list.isEmpty()) null else list.toTypedArray()
        }
        val uri = data?.data
        return if (uri != null) arrayOf(uri) else null
