        private fun postToJs(callbackId: String?, payload: JSONObject) {
            val cb = callbackId ?: return
            val js = "window.__nativeBridge && window.__nativeBridge.onResult && window.__nativeBridge.onResult(${JSONObject.quote(cb)}, ${payload.toString()});"
            webView.post {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.KITKAT) {
                    webView.evaluateJavascript(js, null)
                } else {
                    webView.loadUrl("javascript:$js")
