        private fun ok(callbackId: String?, data: JSONObject = JSONObject()) {
            val payload = JSONObject()
            payload.put("ok", true)
            payload.put("data", data)
            postToJs(callbackId, payload)
        }

        private fun err(callbackId: String?, code: String, message: String) {
            val payload = JSONObject()
            payload.put("ok", false)
            payload.put("error", JSONObject().put("code", code).put("message", message))
            postToJs(callbackId, payload)
        }

        @JavascriptInterface
        fun ping(callbackId: String?) {
